        assert deduplicate_sorted([-3, -3, -1, 0, 0, 2]) == [-3, -1, 0, 2]

    def test_mixed_negative_and_positive(self):
        assert deduplicate_sorted([-2, -1, -1, 0, 1, 1, 2]) == [-2, -1, 0, 1, 2]

    def test_single_duplicate_pair(self):
        assert deduplicate_sorted([4, 4]) == [4]

    def test_duplicates_only_at_start(self):
        assert deduplicate_sorted([1, 1, 2, 3, 4]) == [1, 2, 3, 4]

    def test_duplicates_only_at_end(self):
        assert deduplicate_sorted([1, 2, 3, 4, 4]) == [1, 2, 3, 4]

    def test_duplicates_only_in_middle(self):
        assert deduplicate_sorted([1, 2, 2, 3]) == [1, 2, 3]

